import pytest
from playwright.sync_api import expect

def test_hr_admin_update_review_missing_mandatory_field_returns_400(
    hr_admin_page,
    existing_review_id,
    audit_api_client,
    valid_review_payload
):
    page = hr_admin_page
    page.goto(f"/performance-reviews/{existing_review_id}/edit")

    payload_missing_field = {**valid_review_payload, "reviewer_name": ""}
    <helper_fn>.fill_review_form(page, payload_missing_field)

    responses = []
    page.on("response", lambda r: responses.append(r)
            if "/performance-reviews" in r.url else None)

    page.get_by_role("button", name="Save").click()

    api_responses = [r for r in responses if r.request.method in ("PUT", "POST")]
    if api_responses:
        assert api_responses[-1].status == 400, "Expected 400 for missing field"
    else:
        expect(
            page.locator("[data-field='reviewer_name'] .error-msg")
        ).to_be_visible()

    audit_resp = audit_api_client.get(
        f"/audit-records?entity_id={existing_review_id}&action=UPDATE"
    )
    pre_existing = audit_resp.json().get("records", [])
    assert all(
        r.get("status") != "failed_validation" for r in pre_existing
    ), "Unexpected audit record on validation failure"
